public double percentageValue() {
    long result = (long) numerator * 100;
    if (denominator == 0) {
        return Double.POSITIVE_INFINITY;
    } else if (numerator == 0) {
        return 0.0;
    } else {
        return (double) result / denominator;
    }
}

